export { DiffView, type DiffViewProps } from "./diff-view.js";
export { parseDiff, computeDiff, resolveDiffInput } from "@/lib/diff";
export type { ParsedDiff, DiffHunk, DiffChange, ChangeType, DiffInput } from "@/lib/diff";

"use client";

import {
  useState,
  useEffect,
  useRef,
  useMemo,
  type Ref,
  type KeyboardEvent,
} from "react";
import { cn } from "@/lib/utils";
import {
  type ParsedDiff,
  type DiffInputPatch,
  type DiffInputCompare,
  type DiffInputParsed,
  resolveDiffInput,
} from "@/lib/diff";
import { useNavigation } from "@/hooks/use-navigation";
import { Kbd } from "../kbd/kbd.js";
import { UnifiedView } from "./diff-view-unified.js";
import { SplitView } from "./diff-view-split.js";

interface DiffViewBaseProps {
  mode?: "unified" | "split";
  showLineNumbers?: boolean;
  disableWordDiff?: boolean;
  label?: string;
  className?: string;
  ref?: Ref<HTMLElement>;
}

export type DiffViewProps = (
  | DiffInputPatch
  | DiffInputCompare
  | DiffInputParsed
) &
  DiffViewBaseProps;

function FileHeader({
  oldPath,
  newPath,
}: {
  oldPath: string | null;
  newPath: string | null;
}) {
  if (!oldPath && !newPath) return null;

  const label =
    oldPath && newPath && oldPath !== newPath
      ? `${oldPath} → ${newPath}`
      : (oldPath ?? newPath);

  return (
    <div className="px-2 py-1 bg-muted/50 border-b border-border text-muted-foreground truncate">
      {label}
    </div>
  );
}

function DiffContent({
  parsed,
  mode,
  showLineNumbers,
  disableWordDiff,
  activeHunk,
  onKeyDown,
  containerRef,
}: {
  parsed: ParsedDiff;
  mode: "unified" | "split";
  showLineNumbers: boolean;
  disableWordDiff: boolean;
  activeHunk: string | null;
  onKeyDown: (e: KeyboardEvent) => void;
  containerRef: React.RefObject<HTMLElement | null>;
}) {
  if (parsed.hunks.length === 0) {
    return (
      <div
        className="p-4 text-center text-muted-foreground text-sm"
        role="status"
      >
        No changes
      </div>
    );
  }
  if (mode === "split") {
    return (
      <SplitView
        parsed={parsed}
        showLineNumbers={showLineNumbers}
        disableWordDiff={disableWordDiff}
        activeHunk={activeHunk}
        onKeyDown={onKeyDown}
        containerRef={containerRef}
      />
    );
  }
  return (
    <UnifiedView
      parsed={parsed}
      showLineNumbers={showLineNumbers}
      disableWordDiff={disableWordDiff}
      activeHunk={activeHunk}
      onKeyDown={onKeyDown}
      containerRef={containerRef}
    />
  );
}

export function DiffView(props: DiffViewProps) {
  const {
    mode = "unified",
    showLineNumbers = false,
    disableWordDiff = false,
    label,
    className,
    ref,
  } = props;
  const patch = "patch" in props ? props.patch : undefined;
  const before = "before" in props ? props.before : undefined;
  const after = "after" in props ? props.after : undefined;
  const diff = "diff" in props ? props.diff : undefined;
  const parsed = useMemo(
    () => resolveDiffInput(props),
    [patch, before, after, diff],
  );
  const containerRef = useRef<HTMLElement | null>(null);
  const [activeHunk, setActiveHunk] = useState<string | null>(null);

  useEffect(() => {
    setActiveHunk(null);
  }, [parsed.hunks.length]);

  const { onKeyDown: navKeyDown } = useNavigation({
    containerRef,
    role: "button",
    value: activeHunk,
    onValueChange: setActiveHunk,
    upKeys: ["k"],
    downKeys: ["j"],
    wrap: false,
    moveFocus: false,
  });

  const onKeyDown = (e: KeyboardEvent) => {
    if (e.key === "Escape") {
      setActiveHunk(null);
      return;
    }
    navKeyDown(e);
  };

  const activeIndex = activeHunk != null ? Number(activeHunk) : null;
  const announcement =
    activeIndex != null
      ? `Hunk ${activeIndex + 1} of ${parsed.hunks.length}${parsed.hunks[activeIndex]?.heading ? `: ${parsed.hunks[activeIndex].heading}` : ""}`
      : "";

  return (
    <div
      ref={ref as Ref<never>}
      role="region"
      aria-roledescription="diff"
      aria-label={label ?? "Diff output"}
      className={cn(
        "group bg-background border border-border font-mono text-xs",
        className,
      )}
    >
      <FileHeader oldPath={parsed.oldPath} newPath={parsed.newPath} />
      {parsed.hunks.length > 0 && (
        <div className="hidden group-focus-within:flex items-center gap-1 px-2 py-0.5 text-[10px] text-muted-foreground border-b border-border">
          <Kbd size="sm">j</Kbd>
          <Kbd size="sm">k</Kbd>
          <span>navigate hunks</span>
        </div>
      )}
      <DiffContent
        parsed={parsed}
        mode={mode}
        showLineNumbers={showLineNumbers}
        disableWordDiff={disableWordDiff}
        activeHunk={activeHunk}
        onKeyDown={onKeyDown}
        containerRef={containerRef}
      />
      <div className="sr-only" aria-live="polite" aria-atomic="true">
        {announcement}
      </div>
    </div>
  );
}

"use client";

import type { ChangeType, WordSegment } from "@/lib/diff";

export const LINE_STYLE: Record<ChangeType | "hunk", string | undefined> = {
  remove: "text-destructive",
  add: "text-success",
  context: undefined,
  hunk: "text-muted-foreground bg-muted/20 -mx-2 px-2",
};

export const SR_LABEL: Partial<Record<ChangeType, string>> = {
  add: "Added: ",
  remove: "Removed: ",
};

export const LINE_PREFIX: Record<ChangeType, string> = {
  add: "+",
  remove: "-",
  context: " ",
};

export const LINE_NUMBER_CLASS =
  "inline-block w-8 text-right pr-2 text-muted-foreground select-none";

export function formatHunkHeader(hunk: {
  oldStart: number;
  oldCount: number;
  newStart: number;
  newCount: number;
  heading: string;
}): string {
  return `@@ -${hunk.oldStart},${hunk.oldCount} +${hunk.newStart},${hunk.newCount} @@${hunk.heading ? ` ${hunk.heading}` : ""}`;
}

export function LineContent({
  content,
  wordSegments,
  type,
}: {
  content: string;
  wordSegments: WordSegment[] | undefined;
  type: ChangeType;
}) {
  if (!wordSegments || (type !== "add" && type !== "remove")) {
    return <>{content}</>;
  }

  const bg =
    type === "add"
      ? "bg-success/20 rounded-sm"
      : "bg-destructive/20 rounded-sm";
  return (
    <>
      {wordSegments.map((seg, i) =>
        seg.changed ? (
          <span key={i} className={bg}>
            {seg.text}
          </span>
        ) : (
          seg.text
        ),
      )}
    </>
  );
}

"use client";

import { type KeyboardEvent, type RefObject } from "react";
import { cn } from "@/lib/utils";
import { type ParsedDiff, type AnnotatedChange, annotateWordDiff } from "@/lib/diff";
import { LINE_STYLE, SR_LABEL, LINE_PREFIX, LINE_NUMBER_CLASS, formatHunkHeader, LineContent } from "./diff-view-line.js";

export function UnifiedView({ parsed, showLineNumbers, disableWordDiff, activeHunk, onKeyDown, containerRef }: {
  parsed: ParsedDiff;
  showLineNumbers: boolean;
  disableWordDiff: boolean;
  activeHunk: string | null;
  onKeyDown: (e: KeyboardEvent) => void;
  containerRef: RefObject<HTMLElement | null>;
}) {
  return (
    <pre
      ref={containerRef as React.RefObject<never>}
      aria-label="Unified diff"
      aria-keyshortcuts="j k"
      className="p-2 overflow-x-auto focus:outline-none focus-visible:ring-1 focus-visible:ring-ring"
      tabIndex={0}
      onKeyDown={onKeyDown}
    >
      <code>
        {parsed.hunks.map((hunk, hi) => {
          const changes: AnnotatedChange[] = disableWordDiff ? hunk.changes : annotateWordDiff(hunk.changes);
          return (
            <div key={hi}>
              <div
                role="button"
                data-hunk
                tabIndex={-1}
                data-value={String(hi)}
                className={cn(LINE_STYLE.hunk, activeHunk === String(hi) && "ring-1 ring-ring")}
                aria-label={`Change section starting at line ${hunk.oldStart}`}
              >
                {formatHunkHeader(hunk)}
              </div>
              {changes.map((change, ci) => (
                <div key={ci} className={LINE_STYLE[change.type]}>
                  {showLineNumbers && (
                    <>
                      <span className={LINE_NUMBER_CLASS} aria-hidden="true">
                        {change.type !== "add" ? change.oldLine : "\u00a0"}
                      </span>
                      <span className={LINE_NUMBER_CLASS} aria-hidden="true">
                        {change.type !== "remove" ? change.newLine : "\u00a0"}
                      </span>
                    </>
                  )}
                  {SR_LABEL[change.type] && <span className="sr-only">{SR_LABEL[change.type]}</span>}
                  <span aria-hidden="true">{LINE_PREFIX[change.type]}</span>
                  <LineContent content={change.content} wordSegments={change.wordSegments} type={change.type} />
                </div>
              ))}
            </div>
          );
        })}
      </code>
    </pre>
  );
}

"use client";

import { type KeyboardEvent, type RefObject } from "react";
import { cn } from "@/lib/utils";
import { type ParsedDiff, type SplitCell, toSplitRows } from "@/lib/diff";
import { LINE_STYLE, SR_LABEL, LINE_NUMBER_CLASS, formatHunkHeader, LineContent } from "./diff-view-line.js";

function SplitCellView({ side, showLineNumbers, disableWordDiff }: {
  side: SplitCell;
  showLineNumbers: boolean;
  disableWordDiff: boolean;
}) {
  if (side.type === "empty") {
    return <div className="bg-muted/30 pl-2" aria-hidden="true">&nbsp;</div>;
  }

  return (
    <div className={cn("pl-2", LINE_STYLE[side.type])}>
      {showLineNumbers && (
        <span className={LINE_NUMBER_CLASS} aria-hidden="true">
          {side.lineNumber}
        </span>
      )}
      {SR_LABEL[side.type] && <span className="sr-only">{SR_LABEL[side.type]}</span>}
      <LineContent content={side.content} wordSegments={disableWordDiff ? undefined : side.wordSegments} type={side.type} />
    </div>
  );
}

export function SplitView({ parsed, showLineNumbers, disableWordDiff, activeHunk, onKeyDown, containerRef }: {
  parsed: ParsedDiff;
  showLineNumbers: boolean;
  disableWordDiff: boolean;
  activeHunk: string | null;
  onKeyDown: (e: KeyboardEvent) => void;
  containerRef: RefObject<HTMLElement | null>;
}) {
  const rows = toSplitRows(parsed.hunks, !disableWordDiff);

  let hunkIndex = -1;

  return (
    <div
      ref={containerRef as React.RefObject<never>}
      aria-label="Split diff"
      aria-keyshortcuts="j k"
      className="overflow-x-auto focus:outline-none focus-visible:ring-1 focus-visible:ring-ring"
      tabIndex={0}
      onKeyDown={onKeyDown}
    >
      <pre className="p-2">
        <code>
          {rows.map((row, i) => {
            if (row.kind === "separator") {
              hunkIndex++;
              return (
                <div
                  key={i}
                  role="button"
                  data-hunk
                  tabIndex={-1}
                  data-value={String(hunkIndex)}
                  className={cn(LINE_STYLE.hunk, activeHunk === String(hunkIndex) && "ring-1 ring-ring")}
                  aria-label={`Change section starting at line ${row.oldStart}`}
                >
                  {formatHunkHeader(row)}
                </div>
              );
            }

            return (
              <div key={i} className="grid grid-cols-2 divide-x divide-border">
                <div role="group" aria-label="Old">
                  <SplitCellView side={row.left} showLineNumbers={showLineNumbers} disableWordDiff={disableWordDiff} />
                </div>
                <div role="group" aria-label="New">
                  <SplitCellView side={row.right} showLineNumbers={showLineNumbers} disableWordDiff={disableWordDiff} />
                </div>
              </div>
            );
          })}
        </code>
      </pre>
    </div>
  );
}
